export function getRoleVisualTheme(roleOrUser) {
  const role = typeof roleOrUser === 'string' ? roleOrUser : roleOrUser?.role;
  const themeName = ROLE_THEME_NAMES[role] ?? 'slate';
  return {
    name: themeName,
    role,
    ...ROLE_VISUAL_THEMES[themeName],
  };
}
